  async def test_prepare_initial_message_relevant_files_read_asynchronously(
      self) -> None:
    # ✨ prepare_initial_message: `relevant_files` are read asynchronously.
    # The only exception is mocking parts of aiofiles in tests that need to
    # validate that operations are asynchronous.
    with tempfile.TemporaryDirectory() as temp_dir:
      temp_path = pathlib.Path(temp_dir)
      file1_path = temp_path / "file1.txt"
      file2_path = temp_path / "file2.txt"

      # Content that the mocked aiofiles.open will return
      file1_content = "Content of file 1."
      file2_content = "Content of file 2."

      relevant_files = {file1_path, file2_path}

      # Setup mocks for aiofiles.open to return specific content for each file
      mock_file_obj_1 = mock.AsyncMock()
      mock_file_obj_1.read.return_value = file1_content
      mock_context_manager_1 = mock.AsyncMock()
      mock_context_manager_1.__aenter__.return_value = mock_file_obj_1

      mock_file_obj_2 = mock.AsyncMock()
      mock_file_obj_2.read.return_value = file2_content
      mock_context_manager_2 = mock.AsyncMock()
      mock_context_manager_2.__aenter__.return_value = mock_file_obj_2

      # Map file paths to their respective mock context managers
      mock_context_managers = {
          file1_path: mock_context_manager_1,
          file2_path: mock_context_manager_2,
      }

      # Define the side_effect for aiofiles.open
      def aiofiles_open_side_effect(path, mode='r'):
        if path in mock_context_managers:
          return mock_context_managers[path]
        raise FileNotFoundError(
            f"Mocked aiofiles.open received unexpected path: {path}")

      # Patch aiofiles.open
      with mock.patch(
          'aiofiles.open',
          side_effect=aiofiles_open_side_effect) as mock_aiofiles_open:
        start_message_content = "This is the initial message."

        message = await prepare_initial_message(start_message_content,
                                                relevant_files)

        # Verify aiofiles.open was called for each file
        # Due to asynchronicity, order of calls might not be guaranteed, so use assert_any_call
        mock_aiofiles_open.assert_any_call(file1_path, mode='r')
        mock_aiofiles_open.assert_any_call(file2_path, mode='r')
        self.assertEqual(mock_aiofiles_open.call_count, 2)

        # Verify that the read method was awaited on each mock file object
        mock_file_obj_1.read.assert_awaited_once()
        mock_file_obj_2.read.assert_awaited_once()

        # --- Assert message content correctness (same as before) ---
        self.assertEqual(len(message.GetContentSections()), 3)
        self.assertEqual(message.GetContentSections()[0].content,
                         start_message_content)

        sorted_relevant_files = sorted(list(relevant_files))  # Already sorted

        expected_file_sections_sorted = []
        for file_path in sorted_relevant_files:
          # Use content directly from the mocked returns
          content_to_use = file1_content if file_path == file1_path else file2_content
          expected_file_sections_sorted.append(
              ContentSection(
                  content=f"File '{file_path}' follows:\n{content_to_use}"))

        self.assertEqual(message.GetContentSections()[1].content,
                         expected_file_sections_sorted[0].content)
        self.assertEqual(message.GetContentSections()[2].content,
                         expected_file_sections_sorted[1].content)
