  async def test_run_agent_loop_conversation_has_given_name(self) -> None:
    # ✨ run_agent_loop: The conversation started has name `conversation_name`.
    from agent_loop import AgentLoopFactory
    from agent_loop_options import AgentLoopOptions
    from agent_workflow_options import AgentWorkflowOptions
    from conversation import Conversation, ConversationFactory, ConversationFactoryOptions
    from conversational_ai_test_utils import FakeConversationalAI
    from done_command import DoneValuesValidator
    from test_utils import FakeConfirmationManager, FakeConfirmationState, FakeFileAccessPolicy, FakeSelectionManager
    from validation import ValidationResult, CreateValidationManager
    from typing import Awaitable, Callable, List, Tuple
    from agent_command import Argument, VariableMap, CommandInput, VariableName, VariableValueStr, ArgumentContentType
    from command_registry import CommandRegistry
    from message import ContentSection, Message

    # Spy class for ConversationFactory to record calls to its `New` method.
    # This is used instead of unittest.mock to adhere to the test constraints
    # that "Mock is NOT allowed in this code" for dependencies of code_specs_agent.
    class SpyConversationFactory(ConversationFactory):

      def __init__(self, options: ConversationFactoryOptions):
        super().__init__(options)
        self.new_calls: List[Tuple[str, CommandRegistry]] = []

      def New(self, conversation_name: str,
              command_registry: CommandRegistry) -> Conversation:
        self.new_calls.append((conversation_name, command_registry))
        # Delegate to the real ConversationFactory.New to return a valid Conversation object
        # which is required for the AgentLoop to run without errors.
        return super().New(conversation_name, command_registry)

    # Define minimal fakes for unprovided dependencies, using real implementations
    # or the fakes provided by test_utils and conversational_ai_test_utils.
    test_conversation_name = "test_conversation_name_123"

    # Define a done command response for the fake conversational AI
    done_command_input_for_ai_response = CommandInput(
        command_name="done",
        args=VariableMap(
            {VariableName("output"): VariableValueStr("Test completed")}))
    done_message_from_ai = Message(
        role="assistant",
        content_sections=[
            ContentSection(
                content="Task finished.",
                command=done_command_input_for_ai_response)
        ])
    fake_conversational_ai = FakeConversationalAI(
        scripted_responses={test_conversation_name: [done_message_from_ai]})

    fake_confirmation_manager = FakeConfirmationManager()
    fake_confirmation_state = FakeConfirmationState(
        confirmation_manager=fake_confirmation_manager)
    file_access_policy = FakeFileAccessPolicy()
    selection_manager = FakeSelectionManager()
    validation_manager = CreateValidationManager()

    # Prepare command registry with a dummy validator and no specific arguments
    # as the done command's behavior is not under test here.
    async def dummy_validator(inputs: VariableMap) -> ValidationResult:
      return ValidationResult(True, "", "")

    done_command_arguments: List[Argument] = [
        Argument(
            VariableName("output"),
            ArgumentContentType.STRING,
            "The output of the agent.",
        )
    ]
    command_registry = await prepare_command_registry(done_command_arguments,
                                                      dummy_validator,
                                                      file_access_policy)

    # Prepare start message
    start_message = await prepare_initial_message("Initial message", set())

    # Create the real AgentLoopFactory
    agent_loop_factory = AgentLoopFactory()

    # Create an instance of the SpyConversationFactory.
    # This factory will be passed to AgentWorkflowOptions.
    real_conversation_factory_options = ConversationFactoryOptions()
    spy_conversation_factory = SpyConversationFactory(
        real_conversation_factory_options)

    # Create a dummy Conversation object for the initial AgentLoopOptions.
    # This is a placeholder because run_agent_loop will replace it with the
    # conversation created by the `conversation_factory.New` call.
    dummy_conversation_for_options = Conversation(
        name="dummy_name_for_options",
        unique_id=123,
        command_registry=command_registry,
    )

    agent_loop_options = AgentLoopOptions(
        conversation=dummy_conversation_for_options,
        start_message=start_message,
        command_registry=command_registry,
        confirmation_state=fake_confirmation_state,
        file_access_policy=file_access_policy,
        conversational_ai=fake_conversational_ai,
        validation_manager=validation_manager,
    )

    workflow_options = AgentWorkflowOptions(
        agent_loop_options=agent_loop_options,
        agent_loop_factory=agent_loop_factory,
        conversation_factory=spy_conversation_factory,
        selection_manager=selection_manager)

    # Run the agent loop.
    # The `run_agent_loop` function internally calls `workflow_options.conversation_factory.New`.
    await run_agent_loop(workflow_options, test_conversation_name,
                         start_message, command_registry)

    # Assert that SpyConversationFactory.New was called exactly once
    # with the correct conversation_name and command_registry.
    self.assertEqual(len(spy_conversation_factory.new_calls), 1)
    called_conversation_name, called_command_registry = spy_conversation_factory.new_calls[
        0]
    self.assertEqual(called_conversation_name, test_conversation_name)
    self.assertEqual(called_command_registry, command_registry)
    # ✨

