    # Retrieve the conversation from the conversation_factory by iterating through all of them
    # and finding the one with the matching name.
    found_conversation: Optional[Conversation] = None
    for conv in conversation_factory.GetAll():
      if conv.name() == test_conversation_name:
        found_conversation = conv
        break

    self.assertIsNotNone(
        found_conversation,
        f"Conversation with name '{test_conversation_name}' was not found.")

    # Cast to assure mypy that it's not None after the assert.
    actual_conversation: Conversation = found_conversation  # type: ignore

    # Assert that the first message in the conversation is our expected_start_message.
    # The AgentLoop adds the start_message as the first message to the conversation.
